import { useEffect, useState } from 'react';
import { ChevronLeftIcon, ChevronRightIcon, XMarkIcon } from '@heroicons/react/24/outline';
import {
  knownActions,
  type Announcement,
  type AnnouncementAction,
} from '@/vendor/announcement-core';
import { resolveAnnouncementIcon } from './icons';
import { AnnouncementBody } from './AnnouncementBody';
import { AnnouncementMedia } from './AnnouncementMedia';

/**
 * Which layout to render. `card` (EMPTY_STATE) and `modal` (MODAL) are vertical
 * ‚Äî icon + optional media / title / body / actions, with the close (X) as a
 * flex sibling pinned to the top (`self-start`), exactly as the plugin's
 * `AnnouncementCard`. `banner` (TOP_BANNER / INPUT_BANNER) is a single
 * horizontal row ‚Äî icon, title + body, then actions and X pushed to the right.
 */
export type AnnouncementVariant = 'card' | 'banner' | 'modal';

export interface AnnouncementViewProps {
  announcement: Announcement;
  /**
   * Reserved for future per-locale fallback / series steps. Bodies and action
   * labels arrive already localized from the delivery endpoint, so this is not
   * consumed for text today ‚Äî it's part of the stable prop contract.
   */
  locale?: string;
  variant: AnnouncementVariant;
  /** Invoked when the user activates a (known-type) action button. */
  onAction: (action: AnnouncementAction) => void;
  /** Invoked when the user closes the announcement via the X. */
  onDismiss: () => void;
}

// Class constants mirror the plugin's `AnnouncementCard` 1:1 ‚Äî same spacing,
// radius, font size, and hover behavior ‚Äî with the plugin's design tokens
// swapped for `--ann-*` CSS variables so each consumer (plugin webview / www
// admin) themes the identical markup. Token map: --ann-surface = surface-raised,
// --ann-fg = text-primary, --ann-fg-muted = text-secondary, --ann-fg-subtle =
// text-tertiary, --ann-border = border-subtle, --ann-accent = accent-primary,
// --ann-hover = state-info-bg.
const CONTAINER_BASE =
  'rounded-lg border border-[color:var(--ann-border)] bg-[color:var(--ann-surface)] text-[0.8461rem]';
const ICON_CLASS = 'h-5 w-5 flex-shrink-0 text-[color:var(--ann-fg-muted)]';
const TITLE_CLASS = 'font-medium text-[color:var(--ann-fg)]';
const BODY_CLASS = 'text-[color:var(--ann-fg-muted)]';
const ACTION_BUTTON_CLASS =
  'rounded px-2 py-1 font-medium text-[color:var(--ann-accent)] transition-colors hover:bg-[color:var(--ann-hover)]';
const CLOSE_BUTTON_CLASS =
  'flex-shrink-0 self-start rounded p-0.5 text-[color:var(--ann-fg-subtle)] transition-colors hover:bg-[color:var(--ann-hover)]';
// Carousel step arrows: same subtle tone as the X, disabled when at an end.
const STEP_NAV_BUTTON_CLASS =
  'rounded p-0.5 text-[color:var(--ann-fg-subtle)] transition-colors hover:bg-[color:var(--ann-hover)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:bg-transparent';

/**
 * Pure presentation for a single server-driven `Announcement`, rendered
 * pixel-identical to the plugin's `AnnouncementCard`. Renders the icon,
 * optional media, title, restricted-markdown body (via Streamdown), the
 * client-known action buttons, and an optional dismiss (X). ALL behavior is
 * injected: `onAction`/`onDismiss` callbacks only ‚Äî this component has no
 * routing, adapter, or dispatch dependency, so the plugin webview and the www
 * admin render the identical markup and each wires its own behavior. Colors
 * come from `--ann-*` CSS variables so each consumer themes the same markup.
 */
export function AnnouncementView(props: AnnouncementViewProps) {
  const { announcement, variant, onAction, onDismiss } = props;
  const Icon = resolveAnnouncementIcon(announcement.icon);

  // Multi-step series (carousel): only in the vertical layouts (card/modal).
  // The banner is a single row and can't host a carousel, so it always renders
  // the announcement's top-level title/body. The step index is view-local
  // (resets when a different announcement takes the slot).
  const steps = announcement.steps ?? [];
  const isSeries = variant !== 'banner' && steps.length > 0;
  const [stepIndex, setStepIndex] = useState(0);
  useEffect(() => {
    setStepIndex(0);
  }, [announcement.id]);
  const clampedIndex = Math.min(stepIndex, Math.max(0, steps.length - 1));
  const step = isSeries ? steps[clampedIndex] : undefined;
  // Only render actions whose `type` this client build knows how to handle ‚Äî
  // a forward-compatible server may send an action type we don't recognize;
  // rendering a button for it would be a dead button (the consumer's dispatch
  // has nothing to do), so it's filtered out here.
  const actions = knownActions(announcement);

  const actionButtons =
    actions.length > 0
      ? actions.map((action) => (
          <button
            key={action.id}
            type="button"
            onClick={() => onAction(action)}
            className={ACTION_BUTTON_CLASS}
          >
            {action.label}
          </button>
        ))
      : null;

  const closeButton = announcement.dismissible ? (
    <button type="button" onClick={onDismiss} aria-label="Close" className={CLOSE_BUTTON_CLASS}>
      <XMarkIcon className="h-4 w-4" />
    </button>
  ) : null;

  if (variant === 'banner') {
    // Horizontal one-line layout: [icon][title ¬∑ body] ‚Ä¶ spacer ‚Ä¶ [actions][X].
    return (
      <div className={`${CONTAINER_BASE} flex items-center gap-3 px-3 py-2`}>
        <Icon className={ICON_CLASS} aria-hidden="true" />
        <div className="flex min-w-0 flex-1 items-baseline gap-2">
          <span className={`${TITLE_CLASS} flex-shrink-0`}>{announcement.title}</span>
          <div className={`min-w-0 flex-1 truncate ${BODY_CLASS}`}>
            <AnnouncementBody body={announcement.body} />
          </div>
        </div>
        {actionButtons && (
          <div className="flex flex-shrink-0 flex-wrap items-center gap-2">{actionButtons}</div>
        )}
        {closeButton}
      </div>
    );
  }

  // Vertical layout (card / modal), matching the plugin's `AnnouncementCard`:
  // [icon][ media / title / body / actions ][X], the X being a flex sibling
  // aligned to the top via `self-start` (not absolutely positioned). For a
  // multi-step series the media/title/body come from the current step and a
  // Back / "n / N" / Next nav row sits between the body and the (announcement-
  // level) actions.
  const media = step ? step.media : announcement.media;
  const title = step ? (step.title ?? announcement.title) : announcement.title;
  const body = step ? step.body : announcement.body;

  return (
    <div className={`${CONTAINER_BASE} flex gap-3 p-3`}>
      <Icon className={ICON_CLASS} aria-hidden="true" />
      <div className="min-w-0 flex-1">
        {media && <AnnouncementMedia media={media} className="mb-2" />}
        <div className={TITLE_CLASS}>{title}</div>
        <div className={`mt-1 ${BODY_CLASS}`}>
          <AnnouncementBody body={body} />
        </div>
        {isSeries && steps.length > 1 && (
          <div className="mt-3 flex items-center justify-between text-[color:var(--ann-fg-subtle)]">
            <span className="tabular-nums">
              {clampedIndex + 1} / {steps.length}
            </span>
            <div className="flex items-center gap-1">
              <button
                type="button"
                onClick={() => setStepIndex(clampedIndex - 1)}
                disabled={clampedIndex === 0}
                aria-label="Previous step"
                className={STEP_NAV_BUTTON_CLASS}
              >
                <ChevronLeftIcon className="h-4 w-4" />
              </button>
              <button
                type="button"
                onClick={() => setStepIndex(clampedIndex + 1)}
                disabled={clampedIndex === steps.length - 1}
                aria-label="Next step"
                className={STEP_NAV_BUTTON_CLASS}
              >
                <ChevronRightIcon className="h-4 w-4" />
              </button>
            </div>
          </div>
        )}
        {actionButtons && (
          <div className="mt-2 flex flex-wrap items-center gap-2">{actionButtons}</div>
        )}
      </div>
      {closeButton}
    </div>
  );
}
